package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testIsNullHandlingWithNullStringNull() throws Exception {
        // Use reflection to create CSVFormat instance with nullString = null
        CSVFormat format = CSVFormat.DEFAULT.withNullString(null);
        // isNullHandling() should return false because nullString is null
        assertFalse(format.isNullHandling());
    }

    @Test
    void testIsNullHandlingWithNullStringNonNull() throws Exception {
        // Use withNullString to create CSVFormat instance with non-null nullString
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");
        // isNullHandling() should return true because nullString is non-null
        assertTrue(format.isNullHandling());
    }
}
